function useWorkspaceLocale() {
	const { i18n } = useTranslation();
	return useMemo(() => (i18n.resolvedLanguage ?? i18n.language).startsWith("de") ? workspaceDe : workspaceEn, [i18n.language, i18n.resolvedLanguage]);
}
